import { clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs) {
  return twMerge(clsx(inputs));
}

"use client";
import * as TogglePrimitive from "@radix-ui/react-toggle";
import { cn } from "@/lib/utils";
import { cva } from "class-variance-authority";

const toggleVariants = cva(
  "group/toggle inline-flex items-center justify-center gap-1 rounded-lg text-sm font-medium whitespace-nowrap transition-all outline-none hover:bg-muted hover:text-foreground focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50 aria-pressed:bg-muted data-[state=on]:bg-muted",
  {
    variants: {
      variant: {
        default: "bg-transparent",
        outline: "border border-input bg-transparent hover:bg-muted",
        destructive: "border border-destructive bg-transparent text-destructive hover:bg-destructive/10",
        ghost: "bg-transparent text-muted-foreground hover:bg-muted hover:text-foreground data-[state=on]:bg-muted data-[state=on]:text-foreground",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80 data-[state=on]:bg-secondary/60",
        link: "bg-transparent text-primary underline-offset-4 hover:bg-transparent hover:underline data-[state=on]:underline data-[state=on]:bg-transparent",
      },
      size: {
        default: "h-9 min-w-9 p-2",
        sm: "h-8 min-w-8",
        lg: "h-10 min-w-10 p-2",
      },
    },
    defaultVariants: { variant: "default", size: "default" },
  }
);

function Toggle({ className, variant = "default", size = "default", ...props }) {
  return (
    <TogglePrimitive.Root
      data-slot="toggle"
      className={cn(toggleVariants({ variant, size, className }))}
      {...props}
    />
  );
}

export { Toggle, toggleVariants };

